// app/restaurant/tasks/task-list/task-list.component.ts
import { Component, computed, inject, signal, OnInit } from '@angular/core'; // aggiunto OnInit
import { FormsModule } from '@angular/forms';
import { DatePipe, AsyncPipe, CommonModule } from '@angular/common';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';
import { Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';

import {
  AssignedRole, AssociationType,
  PRIORITY_LABELS, ROLE_LABELS, STATUS_LABELS,
  TaskView, TaskStatus,
  StaffUser  
} from '../../../models';
import { TaskService } from '../../../services/task.service';
import { LucideAngularModule } from 'lucide-angular';
import { AuthService } from '../../../services/Base/auth.service';
import { StaffRole } from '../../../shared/guards/permission.service';

@Component({
  selector: 'app-task-list',
  standalone: true,
  imports: [FormsModule, DatePipe, AsyncPipe, LucideAngularModule, CommonModule],
  templateUrl: './task-list.component.html',
  styleUrls: ['./task-list.component.css']
})
export class TaskListComponent implements OnInit { // implementa OnInit
  private taskService = inject(TaskService);
  private sanitizer = inject(DomSanitizer);
  private router = inject(Router);
  private authService = inject(AuthService);

  // Dati dal servizio
  private allTasks = toSignal(this.taskService.tasksView$, { initialValue: [] as TaskView[] });
  loading$ = this.taskService.loading$;
  staffUsers = signal<StaffUser[]>([]); // già presente

  // Stato UI
  searchQuery = signal('');
  showForm = signal(false);
  editingId = signal<string | null>(null);
  pendingDelete = signal<{ type: 'task'; id: string; label: string } | null>(null);
  copyFeedback = signal<string | null>(null);

  // Dati form per task - esteso con assignedRoles e assignedUserIds
  taskForm = {
    title: '',
    notes: '',
    priority: 3,
    association_type: 'interna' as AssociationType,
    client_name: '',
    assigned_role: 'tutti' as AssignedRole | null,
    assignedRoles: [] as StaffRole[],      // nuovo
    assignedUserIds: [] as string[],       // nuovo
    due_date: '',
    due_time: '',
    due_all_day: false
  };

  assignToAll = signal<boolean>(false); // nuovo
  showUsersExpanded = signal<boolean>(false);

  // Task filtrate
  filteredTasks = computed<TaskView[]>(() => {
    const q = this.searchQuery().toLowerCase().trim();
    if (!q) return this.allTasks();
    return this.allTasks().filter(t =>
      t.title.toLowerCase().includes(q) ||
      (t.notes ?? '').toLowerCase().includes(q) ||
      (t.client_name ?? '').toLowerCase().includes(q)
    );
  });

  // Label helpers
  statusLabel = (status: string): string => {
    if (Object.keys(STATUS_LABELS).includes(status)) {
      return STATUS_LABELS[status as TaskStatus];
    }
    return status;
  };
  roleLabel = (role: string | null): string => {
    if (!role) return 'Tutti';
    return ROLE_LABELS[role] ?? role;
  };
  priorityLabel = (priority: number): string => PRIORITY_LABELS[priority] ?? String(priority);

  // Segnali per i filtri
  filterStatus = signal<TaskStatus | 'all'>('all');
  filterPriority = signal<number | 'all'>('all');

  // Opzioni per i filtri
  readonly statusOptions = [
    { value: 'all', label: 'Tutti' },
    { value: 'da_iniziare', label: 'Da iniziare' },
    { value: 'in_lavorazione', label: 'In lavorazione' },
    { value: 'completata', label: 'Completata' },
  ];

  readonly priorityOptions = [
    { value: 'all', label: 'Tutte' },
    { value: 1, label: 'Minima' },
    { value: 2, label: 'Bassa' },
    { value: 3, label: 'Media' },
    { value: 4, label: 'Alta' },
    { value: 5, label: 'Urgente' },
  ];

  // Reference data
  readonly roles = Object.entries(ROLE_LABELS).map(
    ([value, label]) => ({ value: value as AssignedRole, label })
  );
  readonly priorities = [1, 2, 3, 4, 5];

  async ngOnInit() {
    const staff = await this.taskService.getStaffUsers();
    this.staffUsers.set(staff);
  }

  // Highlight testo
  highlight(text: string): SafeHtml {
    const q = this.searchQuery().trim();
    if (!q) return text;
    const esc = q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const html = text.replace(
      new RegExp(`(${esc})`, 'gi'),
      '<mark>$1</mark>'
    );
    return this.sanitizer.bypassSecurityTrustHtml(html);
  }

  // Navigazione al dettaglio
  goToDetail(id: string) {
    this.router.navigate(['/restaurant/task-detail', id]);
  }

  // Apertura form task
openCreateTaskForm() {
  this.taskForm = {
    title: '', notes: '', priority: 3,
    association_type: 'interna', client_name: '',
    assigned_role: null,
    assignedRoles: [],
    assignedUserIds: [],
    due_date: '',
    due_time: '',           // ← aggiunto
    due_all_day: false      // ← aggiunto
  };
  this.assignToAll.set(false);
  this.editingId.set(null);
  this.showForm.set(true);
}

openEditTaskForm(task: TaskView, event: Event) {
  event.stopPropagation();

  let dueDatePart = '';
  let dueTimePart = '';
  let dueAllDay = task.due_all_day || false;

  if (task.due_date) {
    const date = new Date(task.due_date);
    dueDatePart = date.toISOString().split('T')[0]; // yyyy-mm-dd
    if (!dueAllDay) {
      dueTimePart = date.toTimeString().substring(0, 5); // hh:mm
    }
  }

  this.taskForm = {
    title: task.title,
    notes: task.notes ?? '',
    priority: task.priority,
    association_type: task.association_type,
    client_name: task.client_name ?? '',
    assigned_role: task.assigned_role,
    assignedRoles: task.assignedRoles,
    assignedUserIds: task.assignedUsers.map(u => u.id),
    due_date: dueDatePart,
    due_time: dueTimePart,
    due_all_day: dueAllDay
  };

  this.assignToAll.set(
    task.assigned_role === 'tutti' ||
    (task.assigned_role === null && task.assignedRoles.length === 0 && task.assignedUsers.length === 0)
  );
  this.editingId.set(task.id);
  this.showForm.set(true);
}

  // Salvataggio task
async saveTask() {
  if (!this.taskForm.title.trim()) return;

  // Costruzione due_date
  let dueDatetime = null;
  if (this.taskForm.due_date) {
    const date = this.taskForm.due_date;
    const time = this.taskForm.due_all_day ? '00:00' : (this.taskForm.due_time || '00:00');
    dueDatetime = `${date}T${time}:00`; // formato ISO con secondi
  }

  const payload = {
    title: this.taskForm.title.trim(),
    notes: this.taskForm.notes.trim() || null,
    priority: this.taskForm.priority,
    association_type: this.taskForm.association_type,
    client_name: this.taskForm.association_type === 'cliente'
      ? (this.taskForm.client_name.trim() || null)
      : null,
    due_date: dueDatetime,
    due_all_day: this.taskForm.due_all_day   // ← nuovo campo
  };

  const id = this.editingId();

  if (this.assignToAll()) {
    if (id) {
      await this.taskService.update(id, { ...payload, assigned_role: 'tutti' });
    } else {
      const newTask = await this.taskService.create({ ...payload, assigned_role: 'tutti' });
      if (newTask) {
        this.router.navigate(['/restaurant/task-detail', newTask.id]);
      }
    }
  } else {
    if (id) {
      await this.taskService.updateTaskWithAssignments(
        id,
        { ...payload, assigned_role: null },
        this.taskForm.assignedRoles,
        this.taskForm.assignedUserIds
      );
    } else {
      const newTask = await this.taskService.createTaskWithAssignments(
        { ...payload, assigned_role: null },
        this.taskForm.assignedRoles,
        this.taskForm.assignedUserIds
      );
      if (newTask) {
        this.router.navigate(['/restaurant/task-detail', newTask.id]);
      }
    }
  }
  this.closeForm();
}

  closeForm() { this.showForm.set(false); }

  // Eliminazione
  confirmDeleteTask(id: string, title: string, event: Event) {
    event.stopPropagation();
    this.pendingDelete.set({ type: 'task', id, label: title });
  }

  cancelDelete() { this.pendingDelete.set(null); }

  async executeDelete() {
    const p = this.pendingDelete();
    if (!p) return;
    if (p.type === 'task') {
      await this.taskService.delete(p.id);
    }
    this.pendingDelete.set(null);
  }

  // Copia
  async copyTask(task: TaskView, event: Event) {
    event.stopPropagation();
    await navigator.clipboard.writeText(this.taskService.buildTaskCopyText(task));
    this.flashCopy('Task copiata negli appunti ✓');
  }

  private flashCopy(msg: string) {
    this.copyFeedback.set(msg);
    setTimeout(() => this.copyFeedback.set(null), 2500);
  }

  trackById = (_: number, item: { id: string }) => item.id;

  isTaskVisible(task: TaskView): boolean {
    const role = this.authService.getStaffRole() as StaffRole | null;
    const isOwner = this.authService.isOwner();
    const isManager = this.authService.isManager();
    const userId = this.authService.currentUserValue?.id;
    if (!userId) return false;
    return this.taskService.isTaskVisibleForUser(task, userId, role, isOwner || isManager);
  }

  // Signal delle task visibili
  visibleTasks = computed(() => {
    return this.filteredTasks().filter(task => this.isTaskVisible(task));
  });

  // Metodi per i toggle nel form
  toggleRole(role: StaffRole, event: Event) {
    const checked = (event.target as HTMLInputElement).checked;
    if (checked) {
      this.taskForm.assignedRoles = [...this.taskForm.assignedRoles, role];
    } else {
      this.taskForm.assignedRoles = this.taskForm.assignedRoles.filter((r: StaffRole) => r !== role);
    }
    if (this.assignToAll()) {
      this.assignToAll.set(false);
    }
  }

  toggleUser(userId: string, event: Event) {
    const checked = (event.target as HTMLInputElement).checked;
    if (checked) {
      this.taskForm.assignedUserIds = [...this.taskForm.assignedUserIds, userId];
    } else {
      this.taskForm.assignedUserIds = this.taskForm.assignedUserIds.filter((id: string) => id !== userId);
    }
    if (this.assignToAll()) {
      this.assignToAll.set(false);
    }
  }

  onAssignToAllChange() {
    if (this.assignToAll()) {
      this.taskForm.assignedRoles = [];
      this.taskForm.assignedUserIds = [];
      this.taskForm.assigned_role = 'tutti';
    } else {
      this.taskForm.assigned_role = null;
    }
  }

  // KPI calcolati sulle task visibili (senza filtri)
  totalTasks = computed(() => this.visibleTasks().length);
  todoTasks = computed(() => this.visibleTasks().filter(t => t.status === 'da_iniziare').length);
  inProgressTasks = computed(() => this.visibleTasks().filter(t => t.status === 'in_lavorazione').length);
  completedTasks = computed(() => this.visibleTasks().filter(t => t.status === 'completata').length);

  // Task filtrate per stato e priorità
  filteredByStatusAndPriority = computed(() => {
    const tasks = this.visibleTasks();
    const status = this.filterStatus();
    const priority = this.filterPriority();
    
    return tasks.filter(task => {
      if (status !== 'all' && task.status !== status) return false;
      if (priority !== 'all' && task.priority !== priority) return false;
      return true;
    });
  });

  // Metodi per cambiare i filtri
  setFilterStatus(status: TaskStatus | 'all') {
    this.filterStatus.set(status);
  }

  setFilterPriority(priority: number | 'all') {
    this.filterPriority.set(priority);
  }

  resetFilters() {
    this.filterStatus.set('all');
    this.filterPriority.set('all');
    this.searchQuery.set('');
  }

}